import{_ as r,o as e,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026年6月3日（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-03.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-03.md"}'),o={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-03.md"};function n(i,t,s,d,h,g){return e(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="🫘-黃豆追蹤日報-—-2026年6月3日-週三" tabindex="-1">🫘 黃豆追蹤日報 — 2026年6月3日（週三） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026年6月3日-週三" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026年6月3日（週三）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-06-02 21:00 UTC) <strong>資料截止</strong>：2026-06-02（CBOT 黃豆期貨收盤）</p></blockquote><hr><h2 id="🎯-本日敘事錨點" tabindex="-1">🎯 本日敘事錨點 <a class="header-anchor" href="#🎯-本日敘事錨點" aria-label="Permalink to &quot;🎯 本日敘事錨點&quot;">​</a></h2><p><strong>一句話定調</strong>：美國種植進度超前 + 天氣有利 + 巴西創紀錄出口 + 中國需求疲軟 → 黃豆期貨跌至 $11.64 两周低點，短期供給壓力主導市場。</p><hr><h2 id="🎯-持倉風險提示-每日必填" tabindex="-1">🎯 持倉風險提示（每日必填） <a class="header-anchor" href="#🎯-持倉風險提示-每日必填" aria-label="Permalink to &quot;🎯 持倉風險提示（每日必填）&quot;">​</a></h2><p><strong>持倉方向</strong>：⚪ 觀望 <strong>短期風險</strong>：美國種植進度 87% 超前五年平均 80%，天氣有利 → 供給壓力持續 <strong>潛在觸發條件</strong>：USDA 突發報告 / 荷莫茲海峽升級影響糧運 / 中國大單採購 <strong>現價 vs 倉位成本</strong>：無持倉</p><hr><h2 id="📰-重點追蹤-報告主體-—-5-則" tabindex="-1">📰 重點追蹤（報告主體 — 5 則） <a class="header-anchor" href="#📰-重點追蹤-報告主體-—-5-則" aria-label="Permalink to &quot;📰 重點追蹤（報告主體 — 5 則）&quot;">​</a></h2><h3 id="_1️⃣-cbot-黃豆期貨跌至-11-64-1-40-兩周低點-供給壓力主導" tabindex="-1">1️⃣ CBOT 黃豆期貨跌至 $11.64（-1.40%）：兩周低點，供給壓力主導 <a class="header-anchor" href="#_1️⃣-cbot-黃豆期貨跌至-11-64-1-40-兩周低點-供給壓力主導" aria-label="Permalink to &quot;1️⃣ CBOT 黃豆期貨跌至 $11.64（-1.40%）：兩周低點，供給壓力主導&quot;">​</a></h3><ul><li><strong>6/2 收盤</strong>：$11.6450/bu（-1.40%），前收 $11.8075</li><li><strong>7 月期貨（ZSN26）</strong>：1194&#39;4（+9&#39;2），6/2 結算</li><li><strong>驅動</strong>： <ul><li>美國種植進度 87%（五年平均 80%）→ 供給預期改善</li><li>中國需求疲軟：雖有 2026-2028 年 2,500 萬噸承諾，但核心出口季（9/2026-1/2027）尚未預購</li><li>巴西創紀錄出口：截至 5 月已出口 5,160 萬噸，超越 2025 同期</li><li>基金獲利了結：前期漲幅後的技術性回調</li></ul></li><li><strong>技術面</strong>：月跌 -3.56%，年漲 +11.89%</li><li>⏰ 查詢時間 TST 05:00 | 來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://www.investing.com/commodities/us-soybeans" target="_blank" rel="noreferrer">Investing.com</a></li></ul><h3 id="_2️⃣-usda-種植進度-87-品質-66-good-to-excellent-超前五年平均" tabindex="-1">2️⃣ USDA 種植進度 87% + 品質 66% Good-to-Excellent：超前五年平均 <a class="header-anchor" href="#_2️⃣-usda-種植進度-87-品質-66-good-to-excellent-超前五年平均" aria-label="Permalink to &quot;2️⃣ USDA 種植進度 87% + 品質 66% Good-to-Excellent：超前五年平均&quot;">​</a></h3><ul><li><strong>種植進度</strong>：87%（截至 5/31），前週 79%，五年平均 80%</li><li><strong>出芽率</strong>：65%（五年平均 57%）</li><li><strong>品質評級</strong>： <ul><li>Good-to-Excellent：66%（略低於市場預期 67-68%，去年 67%）</li><li>Fair：29%</li><li>Poor/Very Poor：5%</li></ul></li><li><strong>區域差異</strong>： <ul><li>伊利諾伊、阿肯色、南達科他：條件略優於去年</li><li>俄亥俄：種植 68%（五年平均 75%），因持續降雨落後</li></ul></li><li><strong>影響</strong>：整體利空，優良種植條件壓制價格，但局部延遲可能提供支撐</li><li>⏰ 查詢時間 TST 05:00 | 來源：<a href="https://www.farmprogress.com/marketing/crop-progress-corn-soybean-quality-ratings-go-live" target="_blank" rel="noreferrer">FarmProgress</a>、<a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/06/01/crop-progress-corn-93-planted-67-87" target="_blank" rel="noreferrer">DTN/Progressive Farmer</a>、<a href="https://www.profarmer.com/pro-farmer-max/evening-report/evening-report-usdas-first-look-corn-and-soybean-conditions" target="_blank" rel="noreferrer">ProFarmer</a></li></ul><h3 id="_3️⃣-巴西創紀錄出口-5-160-萬噸-全球供給充裕-國際市場競爭加劇" tabindex="-1">3️⃣ 巴西創紀錄出口 5,160 萬噸 + 全球供給充裕：國際市場競爭加劇 <a class="header-anchor" href="#_3️⃣-巴西創紀錄出口-5-160-萬噸-全球供給充裕-國際市場競爭加劇" aria-label="Permalink to &quot;3️⃣ 巴西創紀錄出口 5,160 萬噸 + 全球供給充裕：國際市場競爭加劇&quot;">​</a></h3><ul><li><strong>巴西 2025/26 產量</strong>：1.77-1.82 億噸（歷史新高），+4% YoY</li><li><strong>截至 5 月出口</strong>：5,160 萬噸（超越 2025 同期）</li><li><strong>全年出口預估</strong>：1.121 億噸（Conab），部分預估達 1.17 億噸</li><li><strong>巴西國內壓榨</strong>：受 B15 生物柴油政策推動，壓榨量創新高 → 減少整豆出口</li><li><strong>國際競爭</strong>：巴西價格優勢 + 較低溢價 → 美國出口承壓</li><li><strong>美國出口承諾</strong>：2025/26 出口預測下修，中國 2,500 萬噸承諾落實存疑</li><li>⏰ 查詢時間 TST 05:00 | 來源：<a href="https://www.spglobal.com/energy/en/news-research/latest-news/agriculture/032526-brazil-sets-new-records-as-global-soybean-leader-amid-us-china-trade-tensions" target="_blank" rel="noreferrer">SPGlobal</a>、<a href="https://datamarnews.com/noticias/brazil-breaks-historical-soybean-export-record/" target="_blank" rel="noreferrer">DatamarNews</a>、<a href="https://www.farmprogress.com/soybean/could-brazil-s-soybean-export-hurdles-create-u-s-opportunity-" target="_blank" rel="noreferrer">FarmProgress</a></li></ul><h3 id="_4️⃣-天然氣-3-17-mmbtu-聖嬰機率升高-肥料成本-2027-產量預期" tabindex="-1">4️⃣ 天然氣 $3.17/MMBtu + 聖嬰機率升高：肥料成本 + 2027 產量預期 <a class="header-anchor" href="#_4️⃣-天然氣-3-17-mmbtu-聖嬰機率升高-肥料成本-2027-產量預期" aria-label="Permalink to &quot;4️⃣ 天然氣 $3.17/MMBtu + 聖嬰機率升高：肥料成本 + 2027 產量預期&quot;">​</a></h3><ul><li><strong>天然氣</strong>：7 月合約 $3.167/MMBtu（6/2 收盤），月均預測 $3.57</li><li><strong>肥料成本傳導</strong>：天然氣佔氮肥（尿素/氨）成本 70-85% → 高氣價 = 高肥料成本</li><li><strong>荷莫茲效應</strong>：中東衝突導致全球肥料危機，2026 年肥料價格持續高檔</li><li><strong>聖嬰現象</strong>：2026 下半年聖嬰機率升高 <ul><li>美國：有利降雨，產量可能 +4%</li><li>巴西南部：過量降雨風險</li><li>巴西北部/東北部：乾旱風險</li><li>阿根廷：有利條件</li></ul></li><li>⏰ 查詢時間 TST 05:00 | 來源：<a href="https://kalshi.com/markets/kxnatgasd/natural-gas-daily/kxnatgasd-26jun0317" target="_blank" rel="noreferrer">Kalshi</a>、<a href="https://www.naturalgasintel.com/news/natural-gas-futures-finish-flat-on-sluggish-lng-weather-demand/" target="_blank" rel="noreferrer">NaturalGasIntel</a>、<a href="https://en.clickpetroleoegas.com.br/study-reveals-that-el-nino-is-gaining-strength-in-the-pacific-favoring-the-soybean-crop-in-the-united-states-in-2026-and-increasing-the-risk-hl1402/" target="_blank" rel="noreferrer">ClickPetroleoEGas</a></li></ul><h3 id="_5️⃣-豆油創合約新高-79-09¢-豆粕跌至三周低-326-50-壓榨利潤分化" tabindex="-1">5️⃣ 豆油創合約新高 79.09¢ + 豆粕跌至三周低 $326.50：壓榨利潤分化 <a class="header-anchor" href="#_5️⃣-豆油創合約新高-79-09¢-豆粕跌至三周低-326-50-壓榨利潤分化" aria-label="Permalink to &quot;5️⃣ 豆油創合約新高 79.09¢ + 豆粕跌至三周低 $326.50：壓榨利潤分化&quot;">​</a></h3><ul><li><strong>豆油（7 月）</strong>：79.09¢/lb（+137 點），<strong>合約新高</strong><ul><li>驅動：B15 生物柴油政策 + 全球油脂需求強勁</li></ul></li><li><strong>豆粕（7 月）</strong>：$326.50/ton（-$3.30），三周低點 <ul><li>驅動：養殖需求溫和 + 供給充裕</li></ul></li><li><strong>壓榨利潤</strong>：豆油強 + 豆粕弱 → 壓榨利潤結構性分化</li><li><strong>連鎖影響</strong>：豆油強勢可能支撐整體黃豆需求（壓榨意願提升）</li><li>⏰ 查詢時間 TST 05:00 | 來源：<a href="https://www.profarmer.com/news/after-bell/after-bell-soy-oil-carves-out-fresh-contract-highs" target="_blank" rel="noreferrer">ProFarmer</a>、<a href="https://ycharts.com/indicators/soybean_meal_futures_price" target="_blank" rel="noreferrer">YahooCharts</a></li></ul><hr><h2 id="📈-追蹤速覽-必填" tabindex="-1">📈 追蹤速覽（必填） <a class="header-anchor" href="#📈-追蹤速覽-必填" aria-label="Permalink to &quot;📈 追蹤速覽（必填）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">昨收</th><th style="text-align:center;">現價</th><th style="text-align:center;">日變</th><th style="text-align:center;">週變</th><th style="text-align:center;">月變</th><th style="text-align:center;">持倉方向</th></tr></thead><tbody><tr><td style="text-align:center;">$11.81</td><td style="text-align:center;">$11.65</td><td style="text-align:center;">-1.40%</td><td style="text-align:center;">-2.1%</td><td style="text-align:center;">-3.56%</td><td style="text-align:center;">⚪ 觀望</td></tr></tbody></table><hr><h2 id="📝-多空判斷" tabindex="-1">📝 多空判斷 <a class="header-anchor" href="#📝-多空判斷" aria-label="Permalink to &quot;📝 多空判斷&quot;">​</a></h2><p><strong>看多因子</strong>：</p><ul><li>巴西 B15 政策 → 豆油需求強勁 → 壓榨意願提升</li><li>聖嬰機率升高 → 巴西南部/東北部減產風險</li><li>荷莫茲海峽持續封鎖 → 運費成本上升 → 支撐到岸價</li><li>中國 2,500 萬噸年度承諾（若落實）</li></ul><p><strong>看空因子</strong>：</p><ul><li>美國種植進度 87% 超前五年平均 → 供給充裕</li><li>中國需求疲軟：核心出口季尚未預購</li><li>巴西創紀錄出口 + 價格優勢</li><li>美國舊作庫存 2.10B bu（高檔）</li><li>基金獲利了結壓力</li></ul><p><strong>關鍵事件日曆</strong>：</p><ul><li>下一個 WASDE：2026-06-12（週五）</li><li>USDA 週度種植進度：每週一</li><li>美國 CPI（5 月）：2026-06-10</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th>日期</th><th>內容</th></tr></thead><tbody><tr><td>1</td><td>TradingEconomics</td><td>2026-06-02</td><td>CBOT 黃豆期貨價格</td></tr><tr><td>2</td><td>Investing.com</td><td>2026-06-02</td><td>黃豆期貨交叉驗證</td></tr><tr><td>3</td><td>FarmProgress</td><td>2026-06-01</td><td>USDA 種植進度</td></tr><tr><td>4</td><td>DTN/Progressive Farmer</td><td>2026-06-01</td><td>種植進度詳細</td></tr><tr><td>5</td><td>ProFarmer</td><td>2026-06-01</td><td>品質評級 + 豆油新高</td></tr><tr><td>6</td><td>SPGlobal</td><td>2026-03-25</td><td>巴西創紀錄出口</td></tr><tr><td>7</td><td>DatamarNews</td><td>2026-05</td><td>巴西出口里程碑</td></tr><tr><td>8</td><td>Kalshi</td><td>2026-06-02</td><td>天然氣期貨價格</td></tr><tr><td>9</td><td>ClickPetroleoEGas</td><td>2026-05</td><td>聖嬰現象與黃豆影響</td></tr><tr><td>10</td><td>CaixinGlobal</td><td>2026-05-18</td><td>中國黃豆貿易承諾</td></tr></tbody></table><hr><p><em>報告生成時間：2026-06-03 05:00 TST</em><em>下一份報告預計：2026-06-04 05:00 TST</em></p>',36)])])}const b=r(o,[["render",n]]);export{u as __pageData,b as default};
